LAYER
	NAME "inmuebles_lotes"
	GROUP "Catalogación"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/mpu/mpu/sectores.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, txtmemo, geom FROM catalogacion.inmuebles_lotes) as mpu using unique gid using srid=32718"
	INCLUDE "configuracion/postgresql_mpu_cat.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "gid"
	LABELITEM "txtmemo"
	LABELMAXSCALEDENOM 2000000
	LABELMAXSCALE 2000000
	METADATA
		"wms_group_title" "MPU"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Inmuebles lotes"
		"wms_abstract" "Inmuebles lotes || Municipalidad Provincial de Urubamba - Cusco :: Perú"
		"wms_credit" "MPU"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "812428.8873977852 8527230.292675558 812455.5658878384 8527272.42"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "Inmuebles lotes"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 0 38 115
			WIDTH 2
		END
		LABEL
			COLOR 0 0 0
			FONT "Arial"
			TYPE truetype
			SIZE 10
			POSITION cc
			PARTIALS false
		END
	END
END # Layer